using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerController : MonoBehaviour
{
    public float turnSpeed = 5.0f;
    public float moveSpeed = 5.0f;

    private Rigidbody rb;

    void Start()
    {
        rb = GetComponent<Rigidbody>();
    }

    void FixedUpdate()
    {
        // Turn the cube
        float turnInput = Input.GetAxis("Horizontal");
        Vector3 turnDirection = new Vector3(turnInput, 0, 0);
        Quaternion turnRotation = Quaternion.Euler(0, turnInput * turnSpeed, 0);
        transform.Rotate(turnRotation.eulerAngles);

        // Move the cube
        float moveInput = Input.GetAxis("Vertical");
        Vector3 moveDirection = new Vector3(0, 0, moveInput);
        rb.MovePosition(transform.position + moveDirection * moveSpeed * Time.deltaTime);
    }
}
```

In this script, the `FixedUpdate` method is used instead of `Update` because we're working with physics, and we want to update the movement at a fixed rate (independent of the frame rate).

